import math

def gelu_exact(x: float) -> float:
    """GELU(x) = x * Phi(x) for standard normal Phi."""
    return x * 0.5 * (1.0 + math.erf(x / math.sqrt(2.0)))

for x in [-2.0, -0.5, 0.0, 0.5, 2.0]:
    print(f"x={x:4.1f}  gelu={gelu_exact(x): .4f}")

import torch
import torch.nn as nn

class TransformerFFN(nn.Module):
    def __init__(self, d_model: int = 768, d_ff: int = 3072):
        super().__init__()
        self.fc1 = nn.Linear(d_model, d_ff)
        self.act = nn.GELU()  # approximate='none' for exact erf on recent PyTorch
        self.fc2 = nn.Linear(d_ff, d_model)

    def forward(self, x: torch.Tensor) -> torch.Tensor:
        return self.fc2(self.act(self.fc1(x)))

x = torch.randn(2, 16, 768)
out = TransformerFFN()(x)
assert out.shape == x.shape
